CREATE OR REPLACE FUNCTION public.csfn001_historico_usuario()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$BEGIN
    IF (TG_OP = 'DELETE') THEN
        INSERT INTO public."CSTBH001_USER" (
            "ID_USER", "NR_CPF", "NO_PESSOA", "NR_RG", "EM_PESSOAL", "NR_CELULAR", 
            "ID_CATEGORIA_ACESSO", "TX_SENHA", "LG_ATIVO", "IC_ACAO_REGISTRO", "ID_USER_USUARIO_ACAO_REGISTRO"
        )
        VALUES (
            OLD."ID_USER", OLD."NR_CPF", OLD."NO_PESSOA", OLD."NR_RG", OLD."EM_PESSOAL", nullif(OLD."NR_CELULAR", '')::numeric, 
            OLD."ID_CATEGORIA_ACESSO"::varchar, OLD."TX_SENHA", OLD."LG_ATIVO", 'D', 
            COALESCE(current_setting('app.current_user_id', true)::bigint, OLD."ID_USER")
        );
        RETURN OLD;
    ELSIF (TG_OP = 'UPDATE') THEN
        INSERT INTO public."CSTBH001_USER" (
            "ID_USER", "NR_CPF", "NO_PESSOA", "NR_RG", "EM_PESSOAL", "NR_CELULAR", 
            "ID_CATEGORIA_ACESSO", "TX_SENHA", "LG_ATIVO", "IC_ACAO_REGISTRO", "ID_USER_USUARIO_ACAO_REGISTRO"
        )
        VALUES (
            NEW."ID_USER", NEW."NR_CPF", NEW."NO_PESSOA", NEW."NR_RG", NEW."EM_PESSOAL", nullif(NEW."NR_CELULAR", '')::numeric, 
            NEW."ID_CATEGORIA_ACESSO"::varchar, NEW."TX_SENHA",NEW."LG_ATIVO", 'U', 
            COALESCE(current_setting('app.current_user_id', true)::bigint, NEW."ID_USER")
        );
        RETURN NEW;
    ELSIF (TG_OP = 'INSERT') THEN
        INSERT INTO public."CSTBH001_USER" (
            "ID_USER", "NR_CPF", "NO_PESSOA", "NR_RG", "EM_PESSOAL", "NR_CELULAR", 
            "ID_CATEGORIA_ACESSO", "TX_SENHA", "LG_ATIVO", "IC_ACAO_REGISTRO", "ID_USER_USUARIO_ACAO_REGISTRO"
        )
        VALUES (
            NEW."ID_USER", NEW."NR_CPF", NEW."NO_PESSOA", NEW."NR_RG", NEW."EM_PESSOAL", nullif(NEW."NR_CELULAR", '')::numeric, 
            NEW."ID_CATEGORIA_ACESSO"::varchar, NEW."TX_SENHA", NEW."LG_ATIVO", 'I', 
            COALESCE(current_setting('app.current_user_id', true)::bigint, NEW."ID_USER")
        );
        RETURN NEW;
    END IF;
END;$function$
;

CREATE OR REPLACE FUNCTION public.csfn002_historico_morador()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
