            NEW."LG_ATIVO", 'U', 
            COALESCE(current_setting('app.current_user_id', true)::bigint, NEW."ID_USER")
        );
        RETURN NEW;

    ELSIF (TG_OP = 'INSERT') THEN
        INSERT INTO public."CSTBH002_MORADOR" (
            "ID_MORADOR", "ID_USER", "IC_BLOCO", "NR_APARTAMENTO", 
            "LG_ATIVO", "IC_ACAO_REGISTRO", "ID_USER_AUDITOR"
        )
        VALUES (
            NEW."ID_MORADOR", NEW."ID_USER", NEW."IC_BLOCO", NEW."NR_APARTAMENTO", 
            NEW."LG_ATIVO", 'I', 
            COALESCE(current_setting('app.current_user_id', true)::bigint, NEW."ID_USER")
        );
        RETURN NEW;
    END IF;
END;
$function$
;

